package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, '#', '\\', true, false, "\r\n", null, null, false, true);

        // When
        boolean result = csvFormat.isCommentMarkerSet();

        // Then
        assertTrue(result);

        // Using reflection to test with comment marker as null
        CSVFormat csvFormatNullCommentMarker = new CSVFormat(',', '\"', null, null, '\\', true, false, "\r\n", null, null, false, true);
        assertFalse((boolean) invokePrivateMethod(csvFormatNullCommentMarker, "isCommentMarkerSet"));
    }

    private Object invokePrivateMethod(Object object, String methodName) throws Exception {
        java.lang.reflect.Method method = object.getClass().getDeclaredMethod(methodName);
        method.setAccessible(true);
        return method.invoke(object);
    }
}
